#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long *pref = (long long*)malloc((N+1)*sizeof(long long));
        pref[0] = 0;
        for(int i=1;i<=N;++i){
            int x; scanf("%d", &x);
            pref[i] = pref[i-1] + x;
        }
        int K; scanf("%d", &K);
        while(K--){
            int l, r; scanf("%d %d", &l, &r);
            if(l > r){ int tmp = l; l = r; r = tmp; }
            printf("%lld\n", pref[r] - pref[l-1]);
        }
        free(pref);
    }
    return 0;
}

