import sys

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        pref = [0]
        for _ in range(N):
            pref.append(pref[-1] + int(next(it)))
        K = int(next(it))
        for _ in range(K):
            l = int(next(it))
            r = int(next(it))
            if l > r:
                l, r = r, l
            out_lines.append(str(pref[r] - pref[l-1]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

